export { fetchIPAddress };

import { describe, it, assert, withSubmit } from "./unit_test";
import { fetchIPAddress } from "./main";

await describe("fetchIPAddress", async () => {
  const runCases = [
    { url: "one.one.one.one", expected: ["1.1.1.1", "1.0.0.1"] },
  ];
  const submitCases = runCases.concat([]);

  let testCases = runCases;
  if (withSubmit) {
    testCases = submitCases;
  }

  for (const { url, expected } of testCases) {
    await it(`URL ${url}, should return one of expected IPs`, async () => {
      const actual = await fetchIPAddress(url);
      const matches = expected.some((ip) => ip === actual);
      assert.strictEqual(
        matches,
        true,
        `expected ${JSON.stringify(actual)} to match an IP`,
      );
    });
  }

  const numSkipped = submitCases.length - testCases.length;
  if (numSkipped > 0) {
    console.log(`- Skip: ${numSkipped} test case(s) for submit`);
  }
});

let withSubmit = false; // updated dynamically on the worker

async function describe(description: string, fn: any) {
  console.log(`Running suite: ${description}`);
  console.log("---------------------------------");
  await fn();
}

async function it(description: string, fn: any) {
  try {
    await fn();
    console.log(`✓ Pass: ${description}`);
  } catch (error) {
    console.log(`✘ Fail: ${description}`);
    console.log(`  ${(error as Error)?.message}`);
  }
}

const assert = {
  strictEqual(actual: any, expected: any, message = "") {
    if (actual !== expected) {
      throw new Error(message || `Expected '${actual}' to equal '${expected}'`);
    }
  },

  greaterThan(actual: any, expected: any, message = "") {
    if (actual <= expected) {
      throw new Error(
        message || `Expected '${actual}' to be greater than '${expected}'`,
      );
    }
  },

  lessThan(actual: any, expected: any, message = "") {
    if (actual >= expected) {
      throw new Error(
        message || `Expected '${actual}' to be less than '${expected}'`,
      );
    }
  },

  deepEqual(actual: any, expected: any, message = "") {
    if (!this._isDeepEqual(actual, expected)) {
      throw new Error(
        message ||
          `Expected
  '${JSON.stringify(actual)}'
to deeply equal:
  '${JSON.stringify(expected)}'`,
      );
    }
  },

  doesNotThrow: function (fn: Function, message?: string): void {
    try {
      fn();
    } catch (error) {
      throw new Error(
        message || `Expected function not to throw, but it did: ${error}`,
      );
    }
  },

  throws: function (
    fn: Function,
    expectedError?: string | Error,
    message?: string,
  ): void {
    try {
      fn();
    } catch (error: unknown) {
      if (!expectedError) {
        return;
      }
      if (typeof error === "object" && error !== null && "message" in error) {
        const err = error as Error;
        if (
          typeof expectedError === "string" &&
          err.message !== expectedError
        ) {
          throw new Error(
            message ||
              `Expected error message to be '${expectedError}', but got '${err.message}'.`,
          );
        }

        if (
          expectedError instanceof Error &&
          err.constructor !== expectedError.constructor
        ) {
          throw new Error(
            message ||
              `Expected error of type '${expectedError.constructor.name}', but got '${err.constructor.name}'.`,
          );
        }
      } else {
        throw new Error(
          message ||
            `Expected an error to be thrown, but received an invalid error.`,
        );
      }
      return;
    }
    throw new Error(message || `Expected function to throw, but it didn't.`);
  },

  _isDeepEqual(obj1: any, obj2: any) {
    if (obj1 === obj2) return true;

    if (
      obj1 === null ||
      typeof obj1 !== "object" ||
      obj2 === null ||
      typeof obj2 !== "object"
    ) {
      return false;
    }

    if (Array.isArray(obj1) && Array.isArray(obj2)) {
      if (obj1.length !== obj2.length) return false;
      for (let i = 0; i < obj1.length; i++) {
        if (!this._isDeepEqual(obj1[i], obj2[i])) return false;
      }
      return true;
    }

    const keys1 = Object.keys(obj1);
    const keys2 = Object.keys(obj2);

    if (keys1.length !== keys2.length) return false;

    for (const key of keys1) {
      if (!keys2.includes(key) || !this._isDeepEqual(obj1[key], obj2[key])) {
        return false;
      }
    }

    return true;
  },
};

export { assert, describe, it, withSubmit };

declare module "zod" {
  export interface ZodType<
    Output = any,
    Def extends ZodTypeDef = ZodTypeDef,
    Input = Output,
  > {
    _output: Output;
    parse(input: unknown): Output;
    safeParse(
      input: unknown,
    ): { success: true; data: Output } | { success: false; error: ZodError };
    parseAsync(input: unknown): Promise<Output>;
    safeParseAsync(
      input: unknown,
    ): Promise<
      { success: true; data: Output } | { success: false; error: ZodError }
    >;
    optional(): ZodOptional<this>;
    nullable(): ZodNullable<this>;
    nullish(): ZodNullish<this>;
    default(value: Output): ZodDefault<this>;
    transform<NewOutput>(
      transform: (arg: Output) => NewOutput,
    ): ZodTransform<this, NewOutput>;
    refine<Refined extends Output>(
      check: (data: Output) => data is Refined,
      message?: string | { message: string; path?: (string | number)[] },
    ): ZodRefined<this, Refined>;
    refine(
      check: (data: Output) => boolean,
      message?: string | { message: string; path?: (string | number)[] },
    ): ZodRefined<this, Output>;
  }

  export interface ZodTypeDef {
    typeName: string;
  }

  export class ZodError extends Error {
    issues: ZodIssue[];
    errors: ZodIssue[];
    constructor(issues: ZodIssue[]);
  }

  export interface ZodIssue {
    code: string;
    path: (string | number)[];
    message: string;
  }

  export interface ZodString extends ZodType<string> {
    min(length: number): ZodString;
    max(length: number): ZodString;
    email(): ZodString;
    url(): ZodString;
    regex(regex: RegExp): ZodString;
    trim(): ZodString;
    toLowerCase(): ZodString;
    toUpperCase(): ZodString;
  }

  export interface ZodNumber extends ZodType<number> {
    min(value: number): ZodNumber;
    max(value: number): ZodNumber;
    positive(): ZodNumber;
    negative(): ZodNumber;
    int(): ZodNumber;
    nonnegative(): ZodNumber;
    nonpositive(): ZodNumber;
    multipleOf(value: number): ZodNumber;
    finite(): ZodNumber;
  }

  export interface ZodBoolean extends ZodType<boolean> {}

  export interface ZodNull extends ZodType<null> {}

  export interface ZodUndefined extends ZodType<undefined> {}

  export interface ZodArray<T extends ZodType> extends ZodType<T["_output"][]> {
    min(length: number): ZodArray<T>;
    max(length: number): ZodArray<T>;
    length(length: number): ZodArray<T>;
    nonempty(): ZodArray<T>;
  }

  export interface ZodObject<
    T extends Record<string, ZodType>,
  > extends ZodType<{
    [K in keyof T]: T[K]["_output"];
  }> {
    shape: T;
    extend<U extends Record<string, ZodType>>(shape: U): ZodObject<T & U>;
    merge<U extends ZodObject<any>>(other: U): ZodObject<T & U["shape"]>;
    pick<K extends keyof T>(keys: { [P in K]: true }): ZodObject<Pick<T, K>>;
    omit<K extends keyof T>(keys: { [P in K]: true }): ZodObject<Omit<T, K>>;
    partial(): ZodObject<{
      [K in keyof T]: ZodOptional<T[K]>;
    }>;
    required(): ZodObject<{
      [K in keyof T]: T[K] extends ZodOptional<infer U> ? U : T[K];
    }>;
    strict(): ZodObject<T>;
    passthrough(): ZodObject<T>;
  }

  export interface ZodUnion<
    T extends readonly [ZodType, ...ZodType[]],
  > extends ZodType<T[number]["_output"]> {}

  export interface ZodLiteral<
    T extends string | number | boolean | null | undefined,
  > extends ZodType<T> {}

  export interface ZodEnum<
    T extends readonly [string, ...string[]],
  > extends ZodType<T[number]> {}

  export interface ZodOptional<T extends ZodType> extends ZodType<
    T["_output"] | undefined
  > {}

  export interface ZodNullable<T extends ZodType> extends ZodType<
    T["_output"] | null
  > {}

  export interface ZodNullish<T extends ZodType> extends ZodType<
    T["_output"] | null | undefined
  > {}

  export interface ZodDefault<T extends ZodType> extends ZodType<
    T["_output"]
  > {}

  export interface ZodTransform<
    T extends ZodType,
    Output,
  > extends ZodType<Output> {}

  export interface ZodRefined<
    T extends ZodType,
    Output = T["_output"],
  > extends ZodType<Output> {}

  export interface ZodRecord<
    K extends ZodType = ZodString,
    V extends ZodType = ZodType,
  > extends ZodType<Record<K["_output"], V["_output"]>> {}

  export interface ZodDiscriminatedUnion<
    K extends string,
    T extends readonly ZodObject<any>[],
  > extends ZodType<T[number]["_output"]> {}

  export interface ZodSchema<T = any> extends ZodType<T> {
    _output: T;
  }

  export const z: {
    string(): ZodString;
    number(): ZodNumber;
    boolean(): ZodBoolean;
    null(): ZodNull;
    undefined(): ZodUndefined;
    array<T extends ZodType>(schema: T): ZodArray<T>;
    object<T extends Record<string, ZodType>>(shape: T): ZodObject<T>;
    union<T extends readonly [ZodType, ...ZodType[]]>(schemas: T): ZodUnion<T>;
    literal<T extends string | number | boolean | null | undefined>(
      value: T,
    ): ZodLiteral<T>;
    enum<T extends readonly [string, ...string[]]>(values: T): ZodEnum<T>;
    record<K extends ZodType = ZodString, V extends ZodType = ZodType>(
      keySchema?: K,
      valueSchema?: V,
    ): ZodRecord<K, V>;
    discriminatedUnion<K extends string, T extends readonly ZodObject<any>[]>(
      discriminator: K,
      schemas: T,
    ): ZodDiscriminatedUnion<K, T>;

    ZodError: typeof ZodError;
  };

  export namespace z {
    export type infer<T extends ZodType<any, any, any>> = T["_output"];
  }

  export default z;
}

